import{_ as e,o as d,c as r,ag as o}from"./chunks/framework.BGkQCay2.js";const u=JSON.parse('{"title":"\\"Why Vex?\\" -- Language Comparison","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why-vex.md","filePath":"guide/why-vex.md"}'),a={name:"guide/why-vex.md"};function s(n,t,i,l,h,c){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="why-vex-language-comparison" tabindex="-1">&quot;Why Vex?&quot; -- Language Comparison <a class="header-anchor" href="#why-vex-language-comparison" aria-label="Permalink to &quot;&quot;Why Vex?&quot; -- Language Comparison&quot;">​</a></h1><p>This page compares Vex to other systems programming languages, highlighting where Vex excels and where other languages may still be the better choice.</p><h2 id="vex-vs-rust" tabindex="-1">Vex vs Rust <a class="header-anchor" href="#vex-vs-rust" aria-label="Permalink to &quot;Vex vs Rust&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>Vex</th><th>Rust</th></tr></thead><tbody><tr><td><strong>Learning curve</strong></td><td>Moderate (Go-like syntax)</td><td>Steep (borrow checker, lifetimes)</td></tr><tr><td><strong>Memory safety</strong></td><td>Ownership + VUMM automatic</td><td>Ownership + borrow checker (explicit)</td></tr><tr><td><strong>Concurrency</strong></td><td>Built-in <code>go</code> blocks, M:N scheduler</td><td>async/await, tokio (external)</td></tr><tr><td><strong>SIMD</strong></td><td>Automatic (array math auto-vectorizes)</td><td>Manual intrinsics or portable_simd (nightly)</td></tr><tr><td><strong>GPU</strong></td><td><code>graph fn</code> compiles to Metal/CUDA/SPIR-V/WGSL</td><td>External crates (wgpu, cudarc)</td></tr><tr><td><strong>Compile times</strong></td><td>Fast (demand-driven prelude, incremental)</td><td>Can be slow (monomorphization, proc macros)</td></tr><tr><td><strong>Ecosystem maturity</strong></td><td>New (growing)</td><td>Mature (100K+ crates)</td></tr><tr><td><strong>Standard library</strong></td><td>Batteries included (HTTP, crypto, serde, DB, ML)</td><td>Minimal std, community crates for everything</td></tr><tr><td><strong>Error messages</strong></td><td>Clear and concise</td><td>Excellent (but lots of them)</td></tr><tr><td><strong>FFI</strong></td><td>C ABI, <code>extern &quot;C&quot;</code>, simple linking</td><td>C ABI, <code>extern &quot;C&quot;</code>, build.rs</td></tr></tbody></table><p><strong>Choose Vex when:</strong> You want Rust-level safety with Go-level simplicity, and you need SIMD/GPU acceleration without fighting the type system.</p><p><strong>Choose Rust when:</strong> You need the mature ecosystem, existing crates, or are building safety-critical software with formal verification requirements.</p><h2 id="vex-vs-go" tabindex="-1">Vex vs Go <a class="header-anchor" href="#vex-vs-go" aria-label="Permalink to &quot;Vex vs Go&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>Vex</th><th>Go</th></tr></thead><tbody><tr><td><strong>Memory model</strong></td><td>Ownership + borrowing, no GC</td><td>Garbage collected (tricolor mark-sweep)</td></tr><tr><td><strong>Performance</strong></td><td>Near-C (LLVM-based, no GC pauses)</td><td>Good but GC overhead, value copying</td></tr><tr><td><strong>Generics</strong></td><td>Full generics with contracts</td><td>Generics since 1.18 (limited)</td></tr><tr><td><strong>Error handling</strong></td><td><code>Result&lt;T,E&gt;</code> + <code>?</code> operator</td><td><code>if err != nil</code> (verbose)</td></tr><tr><td><strong>SIMD/GPU</strong></td><td>First-class, auto-vectorization</td><td>None built-in (assembly or CGo)</td></tr><tr><td><strong>Null safety</strong></td><td><code>Option&lt;T&gt;</code> (no nil)</td><td>Nil pointers, nil slices, nil interfaces</td></tr><tr><td><strong>Concurrency</strong></td><td>M:N scheduler, <code>go</code>, channels</td><td>GOMAXPROCS, goroutines, channels</td></tr><tr><td><strong>Standard library</strong></td><td>Comprehensive (HTTP, crypto, DB, serde)</td><td>Comprehensive (HTTP, crypto, but no generics)</td></tr><tr><td><strong>Binary size</strong></td><td>Moderate (LLVM-based)</td><td>Moderate (Go runtime)</td></tr></tbody></table><p><strong>Choose Vex when:</strong> You need Go&#39;s simplicity but without GC pauses, and you want generics, sum types, and SIMD/GPU.</p><p><strong>Choose Go when:</strong> You value extreme compile speed above all else, or your team is already productive in Go and GC pauses are acceptable.</p><h2 id="vex-vs-zig" tabindex="-1">Vex vs Zig <a class="header-anchor" href="#vex-vs-zig" aria-label="Permalink to &quot;Vex vs Zig&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>Vex</th><th>Zig</th></tr></thead><tbody><tr><td><strong>Memory safety</strong></td><td>Ownership + borrowing (safe by default)</td><td>Manual memory management (no safety)</td></tr><tr><td><strong>Safety philosophy</strong></td><td>Safe by default, <code>unsafe</code> opt-out</td><td>Unsafe by default, no guardrails</td></tr><tr><td><strong>Compile-time</strong></td><td>Comptime evaluation, codegen</td><td>Comptime (Turing-complete)</td></tr><tr><td><strong>Cross-compilation</strong></td><td>LLVM targets, good but heavy</td><td>Best-in-class (ships with Clang)</td></tr><tr><td><strong>SIMD</strong></td><td>Auto-vectorization</td><td>Manual <code>@Vector</code> types</td></tr><tr><td><strong>Standard library</strong></td><td>Rich stdlib</td><td>Minimal stdlib by design</td></tr><tr><td><strong>Learning curve</strong></td><td>Moderate</td><td>Moderate to steep</td></tr></tbody></table><p><strong>Choose Vex when:</strong> You want memory safety guarantees and a rich standard library.</p><p><strong>Choose Zig when:</strong> You want maximum control (including allocator strategies), the best cross-compilation story, or you&#39;re writing a C replacement where safety is not the primary concern.</p><h2 id="vex-vs-c" tabindex="-1">Vex vs C++ <a class="header-anchor" href="#vex-vs-c" aria-label="Permalink to &quot;Vex vs C++&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>Vex</th><th>C++</th></tr></thead><tbody><tr><td><strong>Memory safety</strong></td><td>Ownership + borrowing</td><td>Manual, smart pointers (optional)</td></tr><tr><td><strong>Build system</strong></td><td>Built-in (<code>vex compile</code>, <code>vex.toml</code>)</td><td>CMake, Bazel, Meson (external)</td></tr><tr><td><strong>Package management</strong></td><td>Built-in (<code>vex pm</code>)</td><td>vcpkg, Conan, CPM (external)</td></tr><tr><td><strong>Error messages</strong></td><td>Modern, clear</td><td>Template errors notoriously cryptic</td></tr><tr><td><strong>Move semantics</strong></td><td>Move by default</td><td>std::move, rvalue references</td></tr><tr><td><strong>Legacy burden</strong></td><td>Clean slate design</td><td>40 years of backward compatibility</td></tr><tr><td><strong>GPU/SIMD</strong></td><td>First-class</td><td>C++17 parallel algorithms, SYCL, OpenMP</td></tr></tbody></table><p><strong>Choose Vex when:</strong> You&#39;re starting a new project and want modern tooling, safety, and don&#39;t need C++&#39;s ecosystem.</p><p><strong>Choose C++ when:</strong> You have an existing C++ codebase, need specific C++ libraries (Qt, Unreal Engine), or require C++20/23 features.</p><h2 id="vex-vs-mojo" tabindex="-1">Vex vs Mojo <a class="header-anchor" href="#vex-vs-mojo" aria-label="Permalink to &quot;Vex vs Mojo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>Vex</th><th>Mojo</th></tr></thead><tbody><tr><td><strong>Target audience</strong></td><td>Systems programmers</td><td>ML/AI engineers</td></tr><tr><td><strong>Python compat</strong></td><td>No (clean syntax)</td><td>Python superset</td></tr><tr><td><strong>Memory model</strong></td><td>Ownership + VUMM</td><td>Ownership + MLIR-based</td></tr><tr><td><strong>GPU programming</strong></td><td><code>graph fn</code> (multiple backends)</td><td>Built-in GPU support via MLIR</td></tr><tr><td><strong>Standard library</strong></td><td>General-purpose (HTTP, DB, etc.)</td><td>ML-focused (tensors, autograd)</td></tr><tr><td><strong>Open source</strong></td><td>Yes (MIT)</td><td>Partially (some modules proprietary)</td></tr><tr><td><strong>Maturity</strong></td><td>Early</td><td>Early (by Modular)</td></tr></tbody></table><p><strong>Choose Vex when:</strong> You&#39;re building general systems software, web servers, CLI tools, or anything non-ML.</p><p><strong>Choose Mojo when:</strong> You&#39;re primarily doing ML/AI and want Python interoperability.</p><h2 id="feature-matrix" tabindex="-1">Feature Matrix <a class="header-anchor" href="#feature-matrix" aria-label="Permalink to &quot;Feature Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Vex</th><th>Rust</th><th>Go</th><th>Zig</th><th>C++</th><th>Mojo</th></tr></thead><tbody><tr><td>Memory safety</td><td>Yes</td><td>Yes</td><td>GC</td><td>No</td><td>Partial</td><td>Yes</td></tr><tr><td>Ownership model</td><td>VUMM auto</td><td>Explicit</td><td>GC</td><td>Manual</td><td>Manual/Optional</td><td>Yes</td></tr><tr><td>Generics</td><td>Yes (contracts)</td><td>Yes (traits)</td><td>Yes (limited)</td><td>Yes (comptime)</td><td>Yes (templates)</td><td>Yes</td></tr><tr><td>Sum types</td><td>Yes (enums)</td><td>Yes (enums)</td><td>No</td><td>Yes (tagged union)</td><td>std::variant</td><td>Yes</td></tr><tr><td>Pattern matching</td><td>Full</td><td>Full</td><td>No (switch)</td><td>switch</td><td>No (visit)</td><td>Limited</td></tr><tr><td>Auto SIMD</td><td>Yes</td><td>Manual</td><td>No</td><td>Manual</td><td>Partial (STL)</td><td>Yes</td></tr><tr><td>GPU compute</td><td>Yes (SIR)</td><td>External</td><td>No</td><td>External</td><td>External</td><td>Yes</td></tr><tr><td>Async/await</td><td>Yes</td><td>Yes</td><td>No (goroutines)</td><td>No (async/await)</td><td>C++20</td><td>Yes</td></tr><tr><td>Null safety</td><td>Option&lt;T&gt;</td><td>Option&lt;T&gt;</td><td>No (nil)</td><td>Optional type</td><td>std::optional</td><td>Optional</td></tr><tr><td>Package manager</td><td>Built-in</td><td>Cargo</td><td>Go modules</td><td>Built-in</td><td>External</td><td>External</td></tr><tr><td>Compiler backend</td><td>LLVM 21</td><td>LLVM</td><td>Custom</td><td>LLVM</td><td>LLVM/GCC</td><td>MLIR</td></tr><tr><td>License</td><td>MIT</td><td>MIT/Apache2</td><td>BSD</td><td>MIT</td><td>(various)</td><td>Proprietary</td></tr></tbody></table><h2 id="when-vex-is-the-right-choice" tabindex="-1">When Vex is the Right Choice <a class="header-anchor" href="#when-vex-is-the-right-choice" aria-label="Permalink to &quot;When Vex is the Right Choice&quot;">​</a></h2><ul><li>Building a new web service where GC pauses are unacceptable</li><li>Writing performance-critical code that needs SIMD or GPU acceleration</li><li>Developing cross-platform CLI tools with a single codebase</li><li>Systems programming where memory safety is required but Rust&#39;s complexity is too high</li><li>Data processing pipelines that benefit from auto-vectorization</li><li>Any project where you want Rust&#39;s safety with Go&#39;s simplicity</li></ul><h2 id="when-vex-is-not-the-right-choice-yet" tabindex="-1">When Vex is NOT the Right Choice (Yet) <a class="header-anchor" href="#when-vex-is-not-the-right-choice-yet" aria-label="Permalink to &quot;When Vex is NOT the Right Choice (Yet)&quot;">​</a></h2><ul><li>Projects requiring a mature ecosystem (Vex is new -- the package ecosystem is small)</li><li>When you absolutely need a specific C++/Rust library with no Vex equivalent</li><li>Embedded systems with &lt; 64KB RAM (Vex&#39;s runtime has a minimum footprint)</li><li>When your team is already highly productive in another language with no compelling reason to switch</li></ul>',28)])])}const m=e(a,[["render",s]]);export{u as __pageData,m as default};
